<template>
  <div
    v-if="visible"
    class="fixed inset-0 z-50 flex items-center justify-center bg-black/70 px-4 backdrop-blur-sm"
  >
    <div class="w-full max-w-md rounded-2xl border border-case-border bg-case-surface p-6 shadow-2xl shadow-black/60">
      <p class="text-xs font-semibold uppercase tracking-[0.3em] text-primary">Confirmation</p>
      <h3 class="mt-3 text-xl font-semibold text-white">{{ title }}</h3>
      <p class="mt-3 text-sm leading-7 text-gray-500">{{ description }}</p>

      <div class="mt-6 flex flex-col-reverse gap-3 sm:flex-row sm:justify-end">
        <button
          type="button"
          class="rounded-xl border border-case-border px-4 py-2.5 text-sm font-semibold text-gray-400 transition hover:bg-case-elevated hover:text-gray-200"
          @click="$emit('cancel')"
        >
          {{ cancelText }}
        </button>
        <button
          type="button"
          class="rounded-xl bg-primary px-4 py-2.5 text-sm font-semibold text-black transition hover:bg-amber-500"
          @click="$emit('confirm')"
        >
          {{ confirmText }}
        </button>
      </div>
    </div>
  </div>
</template>

<script>
  export default {
    name: "ConfirmationDialog",
    emits: ["cancel", "confirm"],
    props: {
      visible:     { type: Boolean, default: false },
      title:       { type: String,  required: true },
      description: { type: String,  required: true },
      confirmText: { type: String,  default: "Confirm" },
      cancelText:  { type: String,  default: "Cancel" },
    },
  };
</script>
