<template>
  <div class="min-h-screen bg-case-bg px-6 py-10 sm:px-10 lg:px-12">
    <header class="mb-10">
      <p class="text-xs uppercase tracking-[0.35em] text-primary">VANTA Platform</p>
      <h1 class="mt-2 text-2xl font-semibold text-white sm:text-3xl">Pick a module</h1>
      <p class="mt-1 text-sm text-gray-500">
        You have access to {{ availableModules.length }} of {{ allModules.length }} modules.
      </p>
    </header>

    <div class="grid gap-5 sm:grid-cols-2 lg:grid-cols-3">
      <router-link
        v-for="mod in allModules"
        :key="mod.key"
        :to="hasAccess(mod.key) ? mod.to : ''"
        :event="hasAccess(mod.key) ? 'click' : ''"
        class="group relative flex flex-col rounded-2xl border border-case-border bg-case-surface p-6 transition"
        :class="hasAccess(mod.key)
          ? 'hover:border-primary/40 hover:bg-case-card cursor-pointer'
          : 'opacity-50 cursor-not-allowed'"
      >
        <div class="flex items-center justify-between">
          <span class="flex h-11 w-11 items-center justify-center rounded-xl bg-primary/10 text-primary">
            <Icon :icon="mod.icon" class="text-2xl" />
          </span>
          <span
            v-if="!hasAccess(mod.key)"
            class="rounded-full bg-case-elevated px-2.5 py-1 text-[10px] font-semibold uppercase tracking-[0.2em] text-gray-500"
          >
            No access
          </span>
        </div>
        <h2 class="mt-5 text-lg font-semibold text-white">{{ mod.title }}</h2>
        <p class="mt-2 text-sm leading-relaxed text-gray-500">{{ mod.description }}</p>
        <ul class="mt-4 space-y-1 text-xs text-gray-600">
          <li v-for="f in mod.features" :key="f" class="flex items-center gap-2">
            <span class="h-1 w-1 rounded-full bg-primary/60"></span>
            {{ f }}
          </li>
        </ul>
      </router-link>
    </div>
  </div>
</template>

<script>
  import { Icon } from "@iconify/vue";

  const MODULES = [
    {
      key: "admin",
      title: "ADMIN",
      icon: "mdi:account-multiple-outline",
      to: "/admin",
      description: "Timekeeping, calendar of activities, and documents tracking system.",
      features: ["Daily Time Record", "Calendar of Activities", "Documents Tracking System"],
    },
    {
      key: "cases",
      title: "Case Monitoring",
      icon: "mdi:shield-search",
      to: "/cases",
      description: "Economic sabotage, ANTI-POGO, organized crime, graft & corruption.",
      features: ["Records", "Operations", "Reports"],
    },
    {
      key: "logistics",
      title: "Logistics & Support",
      icon: "mdi:truck-fast-outline",
      to: "/logistics",
      description: "Asset, supply, and operational support tracking.",
      features: ["Coming soon"],
    },
  ];

  export default {
    name: "ModulesHome",
    components: { Icon },
    computed: {
      currentUser() {
        try {
          return JSON.parse(localStorage.getItem("auth_user") || "null");
        } catch {
          return null;
        }
      },
      allModules() {
        return MODULES;
      },
      availableModules() {
        return MODULES.filter((m) => this.hasAccess(m.key));
      },
    },
    methods: {
      hasAccess(moduleKey) {
        const user = this.currentUser;
        if (!user) return false;
        if (user.role === "admin") return true;
        return Boolean(user.modulePermissions?.[moduleKey]);
      },
    },
  };
</script>
