<template>
  <div class="min-h-screen bg-case-bg p-6 sm:p-8">
    <div class="mx-auto max-w-2xl space-y-6">

      <div class="border-b border-case-border pb-5">
        <p class="text-xs font-semibold uppercase tracking-[0.3em] text-primary">System / User &amp; Account</p>
        <h1 class="mt-2 text-2xl font-semibold text-white">Create Account</h1>
        <p class="mt-1 text-sm text-gray-500">Provision a new user with a role and access permissions.</p>
      </div>

      <div
        v-if="message.text"
        :class="message.type === 'success' ? 'border-emerald-800/50 bg-emerald-950/30 text-emerald-400' : 'border-red-900/50 bg-red-950/30 text-red-400'"
        class="rounded-xl border px-4 py-3 text-sm"
      >
        {{ message.text }}
      </div>

      <form @submit.prevent="handleRegister" class="space-y-6">

        <section class="rounded-xl border border-case-border bg-case-surface p-6">
          <h2 class="mb-5 text-xs font-semibold uppercase tracking-[0.2em] text-gray-500">Credentials</h2>
          <div class="grid gap-4 sm:grid-cols-2">
            <div>
              <label for="username" class="mb-2 block text-sm font-medium text-gray-400">Username</label>
              <input
                id="username"
                v-model.trim="form.username"
                type="text"
                class="w-full rounded-xl border border-case-border bg-case-card px-4 py-3 text-gray-200 outline-none transition placeholder:text-gray-600 focus:border-primary focus:ring-4 focus:ring-primary/10"
                placeholder="agent.name"
              />
            </div>
            <div>
              <label for="email" class="mb-2 block text-sm font-medium text-gray-400">Email address</label>
              <input
                id="email"
                v-model.trim="form.email"
                type="email"
                class="w-full rounded-xl border border-case-border bg-case-card px-4 py-3 text-gray-200 outline-none transition placeholder:text-gray-600 focus:border-primary focus:ring-4 focus:ring-primary/10"
                placeholder="agent@agency.gov"
              />
            </div>
            <div>
              <label for="password" class="mb-2 block text-sm font-medium text-gray-400">Password</label>
              <input
                id="password"
                v-model="form.password"
                type="password"
                class="w-full rounded-xl border border-case-border bg-case-card px-4 py-3 text-gray-200 outline-none transition placeholder:text-gray-600 focus:border-primary focus:ring-4 focus:ring-primary/10"
                placeholder="Create a strong password"
              />
            </div>
            <div>
              <label for="confirmPassword" class="mb-2 block text-sm font-medium text-gray-400">Confirm password</label>
              <input
                id="confirmPassword"
                v-model="form.confirmPassword"
                type="password"
                class="w-full rounded-xl border border-case-border bg-case-card px-4 py-3 text-gray-200 outline-none transition placeholder:text-gray-600 focus:border-primary focus:ring-4 focus:ring-primary/10"
                placeholder="Re-enter password"
              />
            </div>
          </div>
        </section>

        <section class="rounded-xl border border-case-border bg-case-surface p-6">
          <h2 class="mb-5 text-xs font-semibold uppercase tracking-[0.2em] text-gray-500">Role &amp; Permissions</h2>
          <div class="grid gap-4 sm:grid-cols-2">
            <div>
              <label for="role" class="mb-2 block text-sm font-medium text-gray-400">Role</label>
              <select
                id="role"
                v-model="form.role"
                class="w-full rounded-xl border border-case-border bg-case-card px-4 py-3 text-gray-200 outline-none transition focus:border-primary focus:ring-4 focus:ring-primary/10 appearance-none cursor-pointer"
              >
                <option value="admin">Admin</option>
                <option value="officer">Officer</option>
                <option value="viewer">Viewer</option>
              </select>
            </div>
            <div>
              <p class="mb-2 text-sm font-medium text-gray-400">Permissions</p>
              <div class="space-y-2.5 rounded-xl border border-case-border bg-case-card p-4">
                <label class="flex cursor-pointer items-start gap-3 text-sm text-gray-400">
                  <input v-model="form.permissions.createReports"       type="checkbox" class="mt-1 h-4 w-4 rounded border-case-border bg-case-elevated text-primary focus:ring-primary/30" />
                  <span>Create reports</span>
                </label>
                <label class="flex cursor-pointer items-start gap-3 text-sm text-gray-400">
                  <input v-model="form.permissions.editIncidents"        type="checkbox" class="mt-1 h-4 w-4 rounded border-case-border bg-case-elevated text-primary focus:ring-primary/30" />
                  <span>Edit incidents</span>
                </label>
                <label class="flex cursor-pointer items-start gap-3 text-sm text-gray-400">
                  <input v-model="form.permissions.deleteRecords"        type="checkbox" class="mt-1 h-4 w-4 rounded border-case-border bg-case-elevated text-primary focus:ring-primary/30" />
                  <span>Delete records</span>
                </label>
                <label class="flex cursor-pointer items-start gap-3 text-sm text-gray-400">
                  <input v-model="form.permissions.viewConfidentialData" type="checkbox" class="mt-1 h-4 w-4 rounded border-case-border bg-case-elevated text-primary focus:ring-primary/30" />
                  <span>View confidential data</span>
                </label>
              </div>
            </div>
          </div>
        </section>

        <label class="flex cursor-pointer items-start gap-3 text-sm text-gray-500">
          <input
            v-model="form.acceptTerms"
            type="checkbox"
            class="mt-1 h-4 w-4 rounded border-case-border bg-case-card text-primary focus:ring-primary/30"
          />
          <span>I confirm this account should be created with the selected role and permissions.</span>
        </label>

        <div class="flex items-center justify-end gap-3">
          <button
            type="button"
            @click="$router.back()"
            class="rounded-xl border border-case-border px-4 py-2.5 text-sm font-medium text-gray-400 transition hover:bg-case-elevated hover:text-gray-200"
          >
            Cancel
          </button>
          <button
            type="submit"
            :disabled="isSubmitting"
            class="rounded-xl bg-primary px-5 py-2.5 text-sm font-semibold text-black transition hover:bg-amber-500 disabled:cursor-not-allowed disabled:opacity-50"
          >
            {{ isSubmitting ? "Saving..." : "Create user" }}
          </button>
        </div>

      </form>
    </div>
  </div>
</template>

<script>
  import API from "@/services/api";

  export default {
    name: "RegisterPage",
    data() {
      return {
        isSubmitting: false,
        message: { type: "", text: "" },
        form: {
          username:       "",
          email:          "",
          password:       "",
          confirmPassword: "",
          role:           "officer",
          permissions: {
            createReports:       false,
            editIncidents:        false,
            deleteRecords:        false,
            viewConfidentialData: false,
          },
          acceptTerms: false,
        },
      };
    },
    methods: {
      async handleRegister() {
        this.message = { type: "", text: "" };

        if (!this.form.username || !this.form.email || !this.form.password) {
          this.message = { type: "error", text: "Username, email, and password are required." };
          return;
        }
        if (this.form.password !== this.form.confirmPassword) {
          this.message = { type: "error", text: "Password confirmation does not match." };
          return;
        }
        if (!this.form.acceptTerms) {
          this.message = { type: "error", text: "Confirm the selected role and permissions before creating the user." };
          return;
        }

        this.isSubmitting = true;
        try {
          const response = await API.post("/auth/register", {
            username:    this.form.username,
            email:       this.form.email,
            password:    this.form.password,
            role:        this.form.role,
            permissions: { ...this.form.permissions },
          });
          this.message = { type: "success", text: response.data.message || "User created successfully." };
          this.form = {
            username: "", email: "", password: "", confirmPassword: "",
            role: "officer",
            permissions: { createReports: false, editIncidents: false, deleteRecords: false, viewConfidentialData: false },
            acceptTerms: false,
          };
        } catch (error) {
          this.message = {
            type: "error",
            text: error.response?.data?.message || "Unable to save the user right now.",
          };
        } finally {
          this.isSubmitting = false;
        }
      },
    },
  };
</script>
